// Trigger-gap repair for `set_state`.
//
// The two per-index `forall|i: int| ... ==> self.page_array@[i] =~= old(self).page_array@[i]`
// ensures (one for each run) trigger only on `post1_self_.page_array@[i]` and
// `post2_self_.page_array@[i]` respectively, so z3 never lines them up.
// They do share the trigger `pre_self_.page_array@[i]`, so we chain through
// `pre_self_` to derive pointwise equality, then lift to Seq extensionality.

let idx: int = index as int;

// Off-index: each post's entry equals pre's entry; force both foralls to
// fire on the same `i` and combine them pointwise.
assert forall|i: int|
    0 <= i < NUM_PAGES && i != idx implies
        post1_self_.page_array@[i] =~= post2_self_.page_array@[i]
by {
    assert(post1_self_.page_array@[i] =~= pre_self_.page_array@[i]);
    assert(post2_self_.page_array@[i] =~= pre_self_.page_array@[i]);
}

// At `idx`, every Page field is pinned by the per-field ensures.
// Chain `=~=` through `pre_self_.page_array@[idx].<field>` for non-state fields,
// and through `state` for the state field.
assert(post1_self_.page_array@[idx].addr =~= pre_self_.page_array@[idx].addr);
assert(post2_self_.page_array@[idx].addr =~= pre_self_.page_array@[idx].addr);
assert(post1_self_.page_array@[idx].is_io_page =~= pre_self_.page_array@[idx].is_io_page);
assert(post2_self_.page_array@[idx].is_io_page =~= pre_self_.page_array@[idx].is_io_page);
assert(post1_self_.page_array@[idx].rev_pointer =~= pre_self_.page_array@[idx].rev_pointer);
assert(post2_self_.page_array@[idx].rev_pointer =~= pre_self_.page_array@[idx].rev_pointer);
assert(post1_self_.page_array@[idx].ref_count =~= pre_self_.page_array@[idx].ref_count);
assert(post2_self_.page_array@[idx].ref_count =~= pre_self_.page_array@[idx].ref_count);
assert(post1_self_.page_array@[idx].owning_container =~= pre_self_.page_array@[idx].owning_container);
assert(post2_self_.page_array@[idx].owning_container =~= pre_self_.page_array@[idx].owning_container);
assert(post1_self_.page_array@[idx].mappings =~= pre_self_.page_array@[idx].mappings);
assert(post2_self_.page_array@[idx].mappings =~= pre_self_.page_array@[idx].mappings);
assert(post1_self_.page_array@[idx].io_mappings =~= pre_self_.page_array@[idx].io_mappings);
assert(post2_self_.page_array@[idx].io_mappings =~= pre_self_.page_array@[idx].io_mappings);
assert(post1_self_.page_array@[idx].state =~= state);
assert(post2_self_.page_array@[idx].state =~= state);

// All eight fields agree, so the two `Page`s at `idx` are =~= equal
// (struct extensionality decomposes into per-field =~=).
assert(post1_self_.page_array@[idx].addr =~= post2_self_.page_array@[idx].addr);
assert(post1_self_.page_array@[idx].is_io_page =~= post2_self_.page_array@[idx].is_io_page);
assert(post1_self_.page_array@[idx].rev_pointer =~= post2_self_.page_array@[idx].rev_pointer);
assert(post1_self_.page_array@[idx].ref_count =~= post2_self_.page_array@[idx].ref_count);
assert(post1_self_.page_array@[idx].owning_container =~= post2_self_.page_array@[idx].owning_container);
assert(post1_self_.page_array@[idx].mappings =~= post2_self_.page_array@[idx].mappings);
assert(post1_self_.page_array@[idx].io_mappings =~= post2_self_.page_array@[idx].io_mappings);
assert(post1_self_.page_array@[idx].state =~= post2_self_.page_array@[idx].state);
assert(post1_self_.page_array@[idx] =~= post2_self_.page_array@[idx]);

// Pointwise equality across the whole array view by case split on `i == idx`.
assert forall|i: int|
    0 <= i < NUM_PAGES implies
        post1_self_.page_array@[i] =~= post2_self_.page_array@[i]
by {
    if i == idx {
        // Settled by the per-field chain above.
    } else {
        // Settled by the off-index forall instantiated above.
    }
}

// Seq extensionality lifts pointwise =~= to view equality.
assert(post1_self_.page_array@ =~= post2_self_.page_array@);
